34.         ["", "ده", "بیست", "سی", "چهل", "پنجاه", "شصت", "هفتاد", "هشتاد", "نود"];
35. 
36.     private static readonly string[] FarsiHundredsMap =
37.         ["", "یکصد", "دویست", "سیصد", "چهارصد", "پانصد", "ششصد", "هفتصد", "هشتصد", "نهصد"];
38. 
39.     /// <inheritdoc />
40.     public string Convert(long number)
41.     {
42.         if (number == 0)
43.         {
44.             return FarsiOnesMap[0];
45.         }
46. 
47.         if (number < 0)
48.         {
